def validate_template_path(template: str) -> None:
    """Check a template path for characters or sequences that could be
    used to escape the template directory or otherwise cause security
    issues, raising `TemplateNotFound` if any are found.
    """
    if not template:
        raise TemplateNotFound(template)

    if "\x00" in template:
        raise TemplateNotFound(template)

    if template[0] in "/\\":
        raise TemplateNotFound(template)

    if len(template) >= 2 and template[1] == ":" and template[0].isalpha():
        raise TemplateNotFound(template)

    for c in template:
        if ord(c) < 32 and c not in "\t\n\r":
            raise TemplateNotFound(template)


